  export default "/** @format */\n\nimport React, { useState } from 'react';\nimport VirtualTable, { Way, Operate } from 'react-tablex';\n\nconst columns = [\n  {\n    label: '序号',\n    fieldkey: 'index',\n    width: 80,\n    custom: VirtualTable.VirtualNo,\n  },\n  {\n    label: '权重',\n    fieldkey: 'weight',\n    require: true,\n    type: 'InputNumber',\n    rules: [\n      { required: true, message: '必填' },\n      {\n        validator({ getStore, rowIndex }, value, callback) {\n          if (rowIndex === 0) {\n            return callback();\n          }\n\n          const store = getStore();\n\n          if (store[rowIndex + 1]?.weight >= value) {\n            return callback('当前权重小于下一列');\n          }\n\n          callback();\n        },\n      },\n    ],\n    watch: [{\n      handle(value, { updateCellData }) {\n        updateCellData(value && Number(value) + 1);\n      },\n      deps: ['weight'],\n      way: Way.Next,\n    }],\n  },\n];\n\nconst Demo = () => {\n  const [dateSource, setDataSource] = useState([{}, {}, {}]);\n\n  const onChange = value => {\n    setDataSource(value);\n  };\n\n  return (\n    <VirtualTable\n      columns={columns}\n      value={dateSource}\n      onChange={onChange}\n      operateItems={[\n        { type: Operate.Add },\n        /**\n         * 控制第一行删除禁用\n         */\n        { type: Operate.Del, disabled: cellProps => cellProps.rowIndex === 0 },\n      ]}\n    />\n  );\n};\n\nexport default Demo;\n";;
  