  export default "import React, { useState } from 'react';\nimport VirtualTable, { Operate } from 'react-tablex';\nimport { Switch } from 'antd';\n\nconst columns = [\n  {\n    label: '序号',\n    fieldkey: 'index',\n    width: 80,\n    custom: VirtualTable.VirtualNo,\n  },\n  {\n    label: '内容',\n    fieldkey: 'type',\n    require: true,\n    rules: [{ required: true, message: '必填' }],\n    type: 'Input',\n  },\n];\n\nconst Demo = () => {\n  const [dateSource, setDataSource] = useState([\n    { type: '内容1' },\n  ]);\n  const [isOperationBtnVisible, setOperationBtnVisible] =\n    useState(false);\n\n  const onChange = (value) => {\n    setDataSource(value);\n  };\n\n  return (\n    <div>\n      <Switch\n        style={{ marginBottom: '20px' }}\n        checkedChildren=\"关闭表格操作项\"\n        unCheckedChildren=\"开启表格操作项\"\n        checked={isOperationBtnVisible}\n        onChange={(value) => setOperationBtnVisible(value)}\n      />\n      <VirtualTable\n        columns={columns}\n        value={dateSource}\n        onChange={onChange}\n        operateItems={[\n          { type: Operate.Add },\n          { type: Operate.Del },\n          { type: Operate.MoveUp },\n          { type: Operate.MoveDown },\n        ]}\n        operateConfig={{ width: 160 }}\n        isOperationBtnVisible={isOperationBtnVisible}\n      />\n    </div>\n  );\n};\n\nexport default Demo;\n";;
  