  export default "import React, { useState } from 'react';\nimport VirtualTable, { Way } from 'react-tablex';\nimport { InputNumber } from 'antd';\n\nconst Demo = () => {\n  const [dateSource, setDataSource] = useState([{}, {}]);\n  const [num, setNum] = useState(1);\n  \n  const getColumns = () => [\n    {\n      label: '序号',\n      fieldkey: 'index',\n      width: 80,\n      custom: VirtualTable.VirtualNo,\n    },\n    {\n      label: '是否开启',\n      fieldkey: 'type',\n      require: true,\n      rules: [{ required: true, message: '必填' }],\n      type: 'Radio',\n      options: [\n        { label: '是', value: true },\n        { label: '否', value: false },\n      ],\n    },\n    {\n      label: '内容',\n      fieldkey: 'content',\n      require: true,\n      rules: [\n        {\n          required: true,\n          message: '必填',\n        },\n      ],\n      type: 'Input',\n      watch: [{\n        handle(value, {updateSelfConfig}) {\n          updateSelfConfig({\n            fieldShow: value,\n          });\n        },\n        deps: ['type'],\n        way: (index) => index === num,\n      }],\n    },\n  ];\n\n  const onChange = (value) => {\n    setDataSource(value);\n  };\n\n  return (\n    <div>\n      <div style={{ marginBottom: '20px' }}>\n        指定行触发watch：\n        <InputNumber value={num} onChange={(value) => setNum(value)} />\n      </div>\n      <VirtualTable columns={getColumns()} value={dateSource} onChange={onChange} />\n    </div>\n  );\n};\n\nexport default Demo;\n";;
  