  export default "/** @format */\n\nimport React, { useState } from 'react';\nimport VirtualTable, { Operate } from 'react-tablex';\nimport { Divider, Radio } from 'antd';\n\nconst RadioButton = Radio.Button;\nconst RadioGroup = Radio.Group;\n\nconst columns = [\n  {\n    label: '内容',\n    fieldkey: 'type',\n    require: true,\n    rules: [{ required: true, message: '必填' }],\n    type: 'Input',\n  },\n];\n\nconst Demo = () => {\n  const [dateSource, setDataSource] = useState([\n    { type: '内容1' },\n    { type: '内容2' },\n    { type: '内容3' },\n    { type: '内容4' },\n    { type: '内容5' },\n    { type: '内容6' },\n    { type: '内容7' },\n    { type: '内容8' },\n    { type: '内容9' },\n  ]);\n  const [selectedRowKeys, setSelectedRowKeys] = useState([]);\n  const [type, setType] = useState('checkbox');\n\n  const onChange = value => {\n    setDataSource(value);\n  };\n\n  const onSelectChange = (selectedRowKeys, selectedRows) => {\n    setSelectedRowKeys(selectedRowKeys);\n    console.log('selectedRowKeys, selectedRows', selectedRowKeys, selectedRows);\n  };\n\n  const onTypeChange = e => {\n    setType(e.target.value);\n    setSelectedRowKeys([]);\n  };\n\n  return (\n    <div>\n      <RadioGroup onChange={onTypeChange} value={type}>\n        <RadioButton value=\"checkbox\">多选</RadioButton>\n        <RadioButton value=\"radio\">单选</RadioButton>\n      </RadioGroup>\n      <Divider />\n      <VirtualTable\n        columns={columns}\n        value={dateSource}\n        onChange={onChange}\n        operateItems={[\n          { type: Operate.Add },\n          { type: Operate.Del },\n          { type: Operate.MoveUp },\n          { type: Operate.MoveDown },\n        ]}\n        operateConfig={{ width: 160 }}\n        isOperationBtnVisible\n        rowSelection={{\n          type,\n          selectedRowKeys,\n          onChange: onSelectChange,\n        }}\n      />\n    </div>\n  );\n};\n\nexport default Demo;\n";;
  