  export default "import { Input, Radio, Switch } from 'antd';\nimport React, { useState } from 'react';\nimport VirtualTable from 'react-tablex';\nimport './index.less';\n\nconst RadioGroup = Radio.Group;\n\n/**\n * 自定义组件\n * 自动接收value, onChange\n */\nconst Custom = ({ value, onChange, width }) => {\n  const { type, content } = value || {};\n\n  const onSelfChange = (params: { type?: boolean; content?: string }) => {\n    onChange({ ...value, ...params });\n  };\n\n  return (\n    <div className=\"custom\">\n      <RadioGroup\n        onChange={(e) => onSelfChange({ type: e.target.value })}\n        value={type}\n      >\n        <Radio value={true}>显示</Radio>\n        <Radio value={false}>隐藏</Radio>\n      </RadioGroup>\n      {type ? (\n        <Input\n          value={content}\n          onChange={(e) => onSelfChange({ content: e.target.value })}\n          style={{ width: `${width}px` }}\n        />\n      ) : null}\n    </div>\n  );\n};\n\nCustom.Display = ({ value }) => {\n  const { type, content } = value || {};\n  return <div className=\"custom-display\">{type ? content : '隐藏中'}</div>;\n};\n\nconst columns = [\n  {\n    label: '序号',\n    fieldkey: 'index',\n    width: 80,\n    custom: VirtualTable.VirtualNo,\n  },\n  {\n    label: '自定义组件',\n    fieldkey: 'custom',\n    require: true,\n    rules: [{ required: true, message: '必填' }],\n    custom: {\n      edit: Custom,\n      display: Custom.Display,\n    },\n    attrs: {\n      width: 150,\n    },\n  },\n];\n\nconst Demo = () => {\n  const [dateSource, setDataSource] = useState([{}]);\n  const [readonly, setReadonly] = useState(false);\n\n  const onChange = (value) => {\n    setDataSource(value);\n  };\n\n  return (\n    <div>\n      <Switch\n        style={{ marginBottom: '20px' }}\n        checkedChildren=\"表格编辑\"\n        unCheckedChildren=\"表格只读\"\n        checked={!readonly}\n        onChange={(value) => setReadonly(!value)}\n      />\n      <VirtualTable\n        readonly={readonly}\n        columns={columns}\n        value={dateSource}\n        onChange={onChange}\n      />\n    </div>\n  );\n};\n\nexport default Demo;\n";;
  