  export default "\n\nimport React, { useState } from 'react';\nimport { InputNumber } from 'antd';\nimport VirtualTable from 'react-tablex';\n\nconst columns = [\n  {\n    label: '序号',\n    fieldkey: 'index',\n    width: 80,\n    custom: VirtualTable.VirtualNo,\n  },\n  {\n    label: '内容',\n    fieldkey: 'type',\n    require: true,\n    rules: [{ required: true, message: '必填' }],\n    type: 'Input',\n  },\n];\n\nconst MAX = 100000\n\nconst Demo = () => {\n    const [dateSource, setDataSource] = useState([]);\n\n  const onChange = value => {\n    setDataSource(value);\n  };\n\n  return (\n    <div>\n      <div style={{ marginBottom: '20px' }}>\n        指定数量：\n        <InputNumber\n          value={dateSource.length}\n          onChange={value => {\n            const num = value <= MAX ? value : MAX;\n            onChange(new Array(num).fill({}));\n          }}\n          max={MAX}\n        />\n      </div>\n      <VirtualTable columns={columns} value={dateSource} onChange={onChange} />\n    </div>\n  );\n};\n\nexport default Demo;";;
  