  export default "/** @format */\n\nimport VirtualTable, { Operate } from 'react-tablex';\nimport React, { useState } from 'react';\n\nconst columns = [\n  {\n    label: '内容',\n    fieldkey: 'type',\n    require: true,\n    rules: [{ required: true, message: '必填' }],\n    type: 'Input',\n  },\n];\n\nconst Demo = () => {\n  const [dateSource, setDataSource] = useState([\n    { type: '内容1' },\n    { type: '内容2' },\n    { type: '内容3' },\n    { type: '内容4' },\n    { type: '内容5' },\n    { type: '内容6' },\n    { type: '内容7' },\n    { type: '内容8' },\n    { type: '内容9' },\n  ]);\n  const [selectedRowKeys, setSelectedRowKeys] = useState([1, 2]);\n\n  const onChange = (value) => {\n    setDataSource(value);\n  };\n\n  const onSelectChange = (selectedRowKeys, selectedRows) => {\n    setSelectedRowKeys(selectedRowKeys);\n    console.log('selectedRowKeys, selectedRows', selectedRowKeys, selectedRows);\n  };\n\n  return (\n    <div>\n      <VirtualTable\n        columns={columns}\n        value={dateSource}\n        onChange={onChange}\n        operateItems={[\n          { type: Operate.Add },\n          { type: Operate.Del },\n          { type: Operate.MoveUp },\n          { type: Operate.MoveDown },\n        ]}\n        isOperationBtnVisible\n        operateConfig={{ width: 160 }}\n        rowSelection={{\n          selectedRowKeys,\n          onChange: onSelectChange,\n          getCheckboxProps: (record) => {\n            return {\n              disabled: record.ssid === 0,\n              ssid: record.ssid,\n            };\n          },\n        }}\n      />\n    </div>\n  );\n};\n\nexport default Demo;\n";;
  