
  import '/Users/zcy/Desktop/pc-virtual-table-front-release-3.0.1/pages/pages/reference/check/code/asyncValidator.tsx?watch=parent';
  export default "/** @format */\n\nimport React, { useRef, useState } from 'react';\nimport VirtualTable from 'react-tablex';\nimport { Button, message } from 'antd';\n\nconst columns = [\n  {\n    label: '序号',\n    fieldkey: 'index',\n    width: 80,\n    custom: VirtualTable.VirtualNo,\n  },\n  {\n    label: '名字（不能重复）',\n    fieldkey: 'type',\n    require: true,\n    rules: [\n      { required: true, message: '必填' },\n      {\n        validator: async (config, value, callback) => {\n          const store = config.getStore();\n\n          /**\n           * 模拟异步\n           * 睡眠1秒钟\n           */\n          await new Promise(resolve => {\n            setTimeout(resolve, 1000);\n          });\n\n          /** 判断是否存在重名 */\n          const exitRepeat = store.reduce((result, { ssid, type }) => {\n            if (config.ssid === ssid) {\n              return result;\n            }\n            if (type === value || result) {\n              return true;\n            }\n            return false;\n          }, false);\n\n          callback?.(exitRepeat ? '名字不能重复' : undefined);\n        },\n      },\n    ],\n    type: 'InputNumber',\n  },\n];\n\nconst Demo = () => {\n  const [dateSource, setDataSource] = useState([]);\n  const virtualTableRef = useRef(null);\n\n  const onChange = value => {\n    setDataSource(value);\n  };\n\n  const submit = () => {\n    virtualTableRef.current?.validate().then(error => {\n      if (!error) {\n        message.success('检验通过');\n      }\n    });\n  };\n\n  return (\n    <div>\n      <Button onClick={submit} style={{ marginBottom: '20px' }}>\n        提交\n      </Button>\n      <VirtualTable\n        ref={virtualTableRef}\n        columns={columns}\n        value={dateSource}\n        onChange={onChange}\n      />\n    </div>\n  );\n};\n\nexport default Demo;\n";;
  