  export default "import React, { useState, useRef } from 'react';\nimport VirtualTable from 'react-tablex';\nimport { Button, message } from 'antd';\n\nconst columns = [\n  {\n    label: '序号',\n    fieldkey: 'index',\n    width: 80,\n    custom: VirtualTable.VirtualNo,\n  },\n  {\n    label: '数字类型字符',\n    fieldkey: 'type',\n    require: true,\n    rules: [\n      { required: true, message: '必填' },\n      { type: 'string', message: '请填写数字', pattern: /^-?\\d+\\.?\\d*$/ }\n    ],\n    type: 'Input',\n  },\n];\n\nconst Demo = () => {\n  const [dateSource, setDataSource] = useState([]);\n  const virtualTableRef = useRef(null);\n\n\n  const onChange = (value) => {\n    setDataSource(value);\n  };\n\n  const submit = () => {\n    virtualTableRef.current?.validate().then(error => {\n      if (!error) {\n        message.success('检验通过');\n      }\n    });\n  };\n\n  return (\n    <div>\n    <Button onClick={submit} style={{ marginBottom: '20px' }}>\n      提交\n    </Button>\n    <VirtualTable\n      ref={virtualTableRef}\n      columns={columns}\n      value={dateSource}\n      onChange={onChange}\n    />\n  </div>\n  );\n};\n\nexport default Demo;\n";;
  